AFTER:
async persistExtractionResults(results: ExtractionResult): Promise<void> {
  const now = Date.now()
  const today = new Date().toISOString().slice(0, 10)
  await this.persistMemories(results.memories, now, today)
  this.persistProfileFacts(results.profileFacts, now, today)
  this.persistRelationships(results.relationships, now)
  this.persistImportantDates(results.importantDates, now)
}

private async persistMemories(memories: ExtractedMemoryItem[], now: number, today: string): Promise<void> {
  if (memories.length === 0) return
  const vectors = await Promise.all(
    memories.map(async (m) => {
      const id = crypto.randomUUID()  // share ID across both stores
      const vector = await this.embedding.embed(m.content)
      this.documentStore.insertMemoryEntry({ id, content: m.content, importance: m.importance, category: m.category, sourceDate: today, createdAt: now })
      return { id, vector, source: 'memory' as VectorSource, content: m.content, createdAt: now }
    }),
  )
  await this.vectorStore.insert(MEMORY_TABLE, vectors)
}
// ... similar private methods for other entity types

WHY: Splits a 68-line function into focused helpers. Also fixes the dual-UUID issue where VectorStore and DocumentStore use different IDs for the same memory, preventing cross-store joins.

